<?php namespace App\Repositories\Fee;use App\Repositories\BaseRepository;use App\Models\Fee\FeeCollection;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class FeeCollectionRepository extends BaseRepository{    public function __construct(FeeCollection $model)    {        $this->model = $model;        parent::__construct($model);    }    public function getByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('payment_date', [$startDate, $endDate])->get();    }    public function getDuePayments(): Collection    {        return $this->query()->where('balance_amount', '>', 0)->where('status', 'partial')->get();    }    public function getPaymentReport(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('payment_date', [$startDate, $endDate])->where('status', 'paid')->get();    }    public function getByPaymentMode(string $paymentMode): Collection    {        return $this->findByField('payment_mode', $paymentMode);    }    public function getByStudentAndDateRange(int $studentId, string $startDate, string $endDate): Collection    {        return $this->query()->where('student_id', $studentId)->whereBetween('payment_date', [$startDate, $endDate])->get();    }    public function getByReceiptNo(string $receiptNo): ?FeeCollection    {        return $this->query()->where('receipt_no', $receiptNo)->first();    }    public function getTotalCollected(string $startDate, string $endDate): float    {        return $this->query()->whereBetween('payment_date', [$startDate, $endDate])->where('status', 'paid')->sum('paid_amount');    }    public function getOutstandingByStudent(int $studentId): float    {        return $this->query()->where('student_id', $studentId)->where('balance_amount', '>', 0)->sum('balance_amount');    }    public function recordPayment(array $data): FeeCollection    {        return $this->create($data);    }    public function reversePayment(int $id): bool    {        return $this->update($id, ['status' => 'reversed', 'reversed_at' => now()]);    }    public function getDailyCollection(string $date): Collection    {        return $this->query()->whereDate('payment_date', $date)->where('status', 'paid')->get();    }    public function getMonthlyCollection(int $year, int $month): Collection    {        return $this->query()->whereYear('payment_date', $year)->whereMonth('payment_date', $month)->where('status', 'paid')->get();    }}